<template>
	<div class="weekly-grid bg-white overflow-x-auto">
		<div :style="{ minWidth: minGridWidth }">
			<!-- Header Row -->
			<div
				class="grid border-b sticky top-0 bg-white z-10"
				:style="gridStyle"
			>
				<div class="p-3 border-r font-semibold text-sm">Employee</div>
				<div
					v-for="(date, index) in weekDates"
					:key="date"
					class="p-2 border-r text-center"
					:class="[
						{ 'border-r-0': index === weekDates.length - 1 },
						isToday(date) ? 'bg-blue-50' : '',
						isWeekend(date) ? 'bg-gray-50' : '',
					]"
				>
					<div class="font-semibold text-sm" :class="isWeekend(date) ? 'text-gray-400' : ''">
						{{ dayName(date) }}
					</div>
					<div class="text-xs text-gray-500">{{ formatDate(date) }}</div>
				</div>
			</div>

			<!-- Loading State -->
			<div v-if="loading" class="flex items-center justify-center p-8">
				<div class="text-gray-400">Loading...</div>
			</div>

			<!-- Empty State -->
			<div v-else-if="employees.length === 0" class="flex items-center justify-center p-8">
				<div class="text-gray-400 text-center">
					<div class="text-4xl mb-2">👥</div>
					<div>No employees found</div>
				</div>
			</div>

			<!-- Employee Rows -->
			<div
				v-else
				v-for="employee in employees"
				:key="employee.name"
				class="grid border-b hover:bg-gray-50"
				:style="gridStyle"
			>
				<!-- Employee Info Cell -->
				<div class="p-3 border-r">
					<div class="font-medium text-sm">{{ employee.employee_name }}</div>
					<div class="text-xs text-gray-500">{{ employee.designation }}</div>
					<div class="mt-2">
						<CapacityBadge :employee="employee.name" />
					</div>
				</div>

				<!-- Day Cells -->
				<DayCell
					v-for="(date, index) in weekDates"
					:key="`${employee.name}-${date}`"
					:employee="employee.name"
					:date="date"
					:assignments="getAssignmentsForCell(employee.name, date)"
					:total-hours="getHoursForCell(employee.name, date)"
					:class="[
						{ 'border-r-0': index === weekDates.length - 1 },
						isToday(date) ? 'bg-blue-50/30' : '',
						isWeekend(date) ? 'bg-gray-50/50' : '',
					]"
					@drop="emit('drop', { employee: employee.name, date: $event })"
					@update-hours="emit('update-hours', $event)"
					@delete="emit('delete', $event)"
				/>
			</div>
		</div>
	</div>
</template>

<script setup>
import { computed, defineProps, defineEmits } from "vue";
import DayCell from "./DayCell.vue";
import CapacityBadge from "./CapacityBadge.vue";

const props = defineProps({
	employees: { type: Array, default: () => [] },
	weekDates: { type: Array, default: () => [] },
	assignments: { type: Array, default: () => [] },
	capacities: { type: Object, default: () => ({}) },
	loading: { type: Boolean, default: false },
});

const emit = defineEmits(["drop", "update-hours", "delete"]);

const employeeColWidth = 220;
const dayColWidth = 180;

const gridStyle = computed(() => ({
	gridTemplateColumns: `${employeeColWidth}px repeat(${props.weekDates.length}, ${dayColWidth}px)`,
}));

const minGridWidth = computed(() => {
	const total = employeeColWidth + props.weekDates.length * dayColWidth;
	return `${total}px`;
});

function getAssignmentsForCell(employee, date) {
	return props.assignments.filter(
		(a) => a.employee === employee && a.assignment_date === date
	);
}

function getHoursForCell(employee, date) {
	if (props.capacities[employee] && props.capacities[employee][date]) {
		return props.capacities[employee][date];
	}
	return 0;
}

function isToday(date) {
	const today = new Date().toISOString().split("T")[0];
	return date === today;
}

function isWeekend(date) {
	const d = new Date(date);
	const day = d.getDay();
	return day === 0 || day === 6; // Sunday or Saturday
}

function dayName(date) {
	const d = new Date(date);
	const days = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
	return days[d.getDay()];
}

function formatDate(date) {
	const d = new Date(date);
	return `${d.getMonth() + 1}/${d.getDate()}`;
}
</script>
