<template>
	<div class="min-h-screen bg-gray-50 flex flex-col">
		<!-- App Header -->
		<header class="bg-white border-b border-gray-200 sticky top-0 z-20">
			<div class="w-full px-4 sm:px-6 lg:px-8">
				<div class="flex items-center justify-between h-16">
					<div class="flex items-center gap-3">
						<CalendarDays class="w-6 h-6 text-purple-600" />
						<h1 class="text-xl font-semibold text-gray-900">
							{{ translate("Weekly Planner") }}
						</h1>
					</div>
					<div class="flex items-center gap-3 sm:gap-4">
						<OutlinerNav />
					</div>
				</div>
			</div>
		</header>

		<!-- Page Content -->
		<div class="weekly-planner flex-1 flex flex-col">
			<!-- Header -->
			<WeeklyPlannerHeader
				@week-change="handleWeekChange"
				@filter-change="handleFilterChange"
				@toggle-resource-pool="store.toggleResourcePool"
				@generate-timesheets="handleGenerateTimesheets"
			/>

			<!-- Main Content -->
			<div class="flex-1 flex overflow-hidden relative">
			<!-- Left Panel: Employee selector + Task pool / Employee tasks -->
			<aside
				v-show="showTaskPool"
				class="w-80 flex-shrink-0 border-r bg-white absolute sm:relative inset-y-0 left-0 z-20 shadow-lg sm:shadow-none h-full flex flex-col"
			>
				<!-- Employee Dropdown -->
				<div class="p-3 border-b bg-gray-50">
					<label class="text-xs font-medium text-gray-500 mb-1 block">{{ translate("Employee") }}</label>
					<select
						:value="store.selectedEmployee || ''"
						@change="handleEmployeeSelect"
						class="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
					>
						<option value="">{{ translate("Unassigned tasks") }}</option>
						<option v-for="emp in store.allEmployees" :key="emp.name" :value="emp.name">
							{{ emp.employee_name }}
						</option>
					</select>
				</div>

				<!-- Task Pool (when no employee selected) -->
				<TaskPool
					v-if="!store.selectedEmployee"
					:tasks="store.taskPool"
					:loading="store.loading"
					class="flex-1 overflow-hidden"
					@dragstart="handleTaskDragStart"
				/>

				<!-- Employee Tasks (when employee selected) -->
				<div v-else class="flex-1 overflow-y-auto">
					<div class="p-3 border-b bg-white sticky top-0">
						<h3 class="font-semibold text-sm text-gray-900">{{ translate("Assigned tasks") }}</h3>
						<p class="text-xs text-gray-500">{{ translate("Tasks for this week") }}</p>
					</div>
					<div v-if="store.loading" class="flex items-center justify-center py-8">
						<div class="text-gray-400 text-sm">{{ translate("Loading...") }}</div>
					</div>
					<div v-else-if="store.selectedEmployeeAssignments.length === 0" class="text-center p-6 text-gray-400">
						<div class="text-3xl mb-2">📋</div>
						<div class="text-sm">{{ translate("No assignments this week") }}</div>
					</div>
					<div v-else class="p-2 space-y-2">
						<div
							v-for="a in store.selectedEmployeeAssignments"
							:key="a.name"
							class="p-3 bg-white border border-gray-200 rounded-lg hover:shadow-sm transition-shadow"
						>
							<div class="font-medium text-sm truncate" :title="a.task_subject">{{ a.task_subject }}</div>
							<div class="text-xs text-gray-500 mt-1">{{ a.project_name || a.project }}</div>
							<div class="flex items-center gap-2 mt-2">
								<span class="text-xs px-2 py-0.5 rounded bg-blue-50 text-blue-700 font-medium">{{ a.allocated_hours }}h</span>
								<span class="text-xs text-gray-400">{{ a.assignment_date }}</span>
								<span class="text-xs px-2 py-0.5 rounded bg-gray-100">{{ a.status }}</span>
							</div>
						</div>
					</div>
				</div>
			</aside>

			<!-- Mobile Left Panel Toggle -->
			<button
				class="sm:hidden absolute top-2 left-2 z-10 px-2 py-1 bg-white border rounded shadow text-xs"
				@click="showTaskPool = !showTaskPool"
			>
				{{ showTaskPool ? '✕ Close' : '📋 Tasks' }}
			</button>

			<!-- Weekly Grid -->
			<WeeklyPlannerGrid
				:employees="store.filteredEmployees"
				:week-dates="store.weekDates"
				:assignments="store.assignments"
				:capacities="store.capacities"
				:loading="store.loading"
				class="flex-1 overflow-auto"
				@drop="handleDrop"
				@update-hours="handleUpdateHours"
				@delete="handleDelete"
			/>
			</div>

			<!-- Resource Pool Summary (Collapsible) -->
			<ResourcePoolSummary
				v-if="store.showResourcePool"
				:data="store.resourcePoolData"
				@select-employee="handleSelectEmployee"
			/>

			<!-- Hour Allocation Modal -->
			<HourAllocationModal
				v-model:show="showHourModal"
				:task="selectedTask"
				:employee="selectedEmployee"
				:date="selectedDate"
				:current-hours="currentDayHours"
				@confirm="handleHourAllocation"
			/>
		</div>
		<BackToDeskButton />
	</div>
</template>

<script setup>
import { ref, onMounted } from "vue";
import { useRouter } from "vue-router";
import { useWeeklyPlanningStore } from "../stores/weeklyPlanningStore";
import { CalendarDays } from "lucide-vue-next";
import OutlinerNav from "@erpnext-projekt-hub/components/OutlinerNav.vue";
import BackToDeskButton from "@erpnext-projekt-hub/components/BackToDeskButton.vue";
import WeeklyPlannerHeader from "../components/weekly-planner/WeeklyPlannerHeader.vue";
import TaskPool from "../components/weekly-planner/TaskPool.vue";
import WeeklyPlannerGrid from "../components/weekly-planner/WeeklyPlannerGrid.vue";
import ResourcePoolSummary from "../components/weekly-planner/ResourcePoolSummary.vue";
import HourAllocationModal from "../components/weekly-planner/HourAllocationModal.vue";

const router = useRouter();
const store = useWeeklyPlanningStore();
const realWindow = typeof globalThis !== "undefined" ? globalThis.window : undefined;
const translate = (text) => {
	return typeof realWindow !== "undefined" && typeof realWindow.__ === "function"
		? realWindow.__(text)
		: text;
};

// Task pool visibility (always visible on desktop, toggle on mobile)
const showTaskPool = ref(window.innerWidth >= 640);

// Modal state
const showHourModal = ref(false);
const selectedTask = ref(null);
const selectedEmployee = ref(null);
const selectedDate = ref(null);
const currentDayHours = ref(0);

// Check Project Manager role on mount
onMounted(async () => {
	// In website SPA routes, frappe.user_roles is not populated (only set in desk context).
	// Use frappe.user_roles if available, otherwise fetch logged user and their roles via API.
	let userRoles =
		window.frappe?.user_roles || window.frappe?.boot?.user?.roles || [];

	if (!userRoles.length) {
		try {
			// First get current logged-in user
			const userRes = await fetch("/api/method/frappe.auth.get_logged_user", {
				headers: { Accept: "application/json" },
			});
			const userData = await userRes.json();
			const uid = userData.message;

			if (uid && uid !== "Guest") {
				// Then fetch roles for that user
				const rolesRes = await fetch(
					`/api/method/frappe.core.doctype.user.user.get_roles?uid=${encodeURIComponent(uid)}`,
					{ headers: { Accept: "application/json" } }
				);
				const rolesData = await rolesRes.json();
				userRoles = rolesData.message || [];
			}
		} catch {
			userRoles = [];
		}
	}

	const hasProjectManagerRole = userRoles.includes("Project Manager");
	const hasProjectsManagerRole = userRoles.includes("Projects Manager");
	const hasSystemManagerRole = userRoles.includes("System Manager");

	if (!hasProjectManagerRole && !hasProjectsManagerRole && !hasSystemManagerRole) {
		const msgprint = window.frappe?.msgprint || frappe?.msgprint;
		if (msgprint) {
			msgprint({
				title: __("Access Denied"),
				message: __(
					"You need Project Manager or Projects Manager role to access Weekly Planner"
				),
				indicator: "red",
			});
		}
		router.push("/project-hub");
		return;
	}

	// Load initial data
	store.fetchWeeklyPlan();
});

function handleWeekChange(direction) {
	store.navigateWeek(direction);
}

function handleFilterChange(filters) {
	if (filters.employee !== undefined) {
		store.setFilter("employee", filters.employee);
	}
	if (filters.projects !== undefined) {
		store.setFilter("projects", filters.projects);
	}
}

function handleEmployeeSelect(e) {
	const value = e.target.value || null;
	store.setFilter("employee", value);
}

function handleTaskDragStart(task) {
	store.draggedTask = task;
}

function handleDrop({ employee, date }) {
	if (!store.draggedTask) return;

	// Open modal with pre-filled data
	selectedTask.value = store.draggedTask;
	selectedEmployee.value = employee;
	selectedDate.value = date;
	currentDayHours.value = store.getHoursForEmployeeAndDate(employee, date);
	showHourModal.value = true;
}

async function handleHourAllocation(hours) {
	try {
		await store.createAssignment(
			selectedEmployee.value,
			selectedDate.value,
			selectedTask.value.name,
			hours
		);

		showHourModal.value = false;
		selectedTask.value = null;
		selectedEmployee.value = null;
		selectedDate.value = null;
		store.draggedTask = null;
	} catch (err) {
		console.error("Failed to allocate hours:", err);
	}
}

async function handleUpdateHours({ assignmentId, hours }) {
	try {
		await store.updateAssignment(assignmentId, hours);
	} catch (err) {
		console.error("Failed to update hours:", err);
	}
}

async function handleDelete(assignmentId) {
	try {
		const confirmed = await new Promise((resolve) => {
			frappe.confirm(
				"Are you sure you want to delete this assignment?",
				() => resolve(true),
				() => resolve(false)
			);
		});

		if (confirmed) {
			await store.deleteAssignment(assignmentId);
		}
	} catch (err) {
		console.error("Failed to delete assignment:", err);
	}
}

function handleSelectEmployee(employee) {
	store.setFilter("employee", employee);
}

async function handleGenerateTimesheets() {
	try {
		const confirmed = await new Promise((resolve) => {
			frappe.confirm(
				"This will create timesheets from all planned assignments for this week. Continue?",
				() => resolve(true),
				() => resolve(false)
			);
		});

		if (confirmed) {
			await store.generateTimesheets();
		}
	} catch (err) {
		console.error("Failed to generate timesheets:", err);
	}
}
</script>
